#include <bits/stdc++.h>
using namespace std;

int main() {
    double salary;
    cin >> salary;

    int p; // 涨幅百分比（整数）
    if (salary <= 400.0) p = 15;
    else if (salary <= 800.0) p = 12;
    else if (salary <= 1200.0) p = 10;
    else if (salary <= 2000.0) p = 7;
    else p = 4;

    double increase = salary * p / 100.0;
    double newSalary = salary + increase;

    cout << fixed << setprecision(2);
    cout << "New salary: " << newSalary << "\n";
    cout << "Increase: " << increase << "\n";
    cout << "Percentage: " << p << " %\n";  // 注意空格
    return 0;
}
